INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 1, 'PABLO, apóstol de Jesucristo por la voluntad de Dios, y el hermano Timoteo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 2, 'A los santos y hermanos fieles en Cristo que están en Colosas: Gracia y paz á vosotros de Dios Padre nuestro, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 3, 'Damos gracias al Dios y Padre del Señor nuestro Jesucristo, siempre orando por vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 4, 'Habiendo oído vuestra fe en Cristo Jesús, y el amor que tenéis á todos los santos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 5, 'A causa de la esperanza que os está guardada en los cielos, de la cual habéis oído ya por la palabra verdadera del evangelio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 6, 'El cual ha llegado hasta vosotros, como por todo el mundo; y fructifica y crece, como también en vosotros, desde el día que oísteis y conocisteis la gracia de Dios en verdad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 7, 'Como habéis aprendido de Epafras, nuestro consiervo amado, el cual es un fiel ministro de Cristo á favor vuestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 8, 'El cual también nos ha declarado vuestro amor en el Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 9, 'Por lo cual también nosotros, desde el día que lo oímos, no cesamos de orar por vosotros, y de pedir que seáis llenos del conocimiento de su voluntad, en toda sabiduría y espiritual inteligencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 10, 'Para que andéis como es digno del Señor, agradándo le en todo, fructificando en toda buena obra, y creciendo en el conocimiento de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 11, 'Corroborados de toda fortaleza, conforme á la potencia de su gloria, para toda tolerancia y largura de ánimo con gozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 12, 'Dando gracias al Padre que nos hizo aptos para participar de la suerte de los santos en luz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 13, 'Que nos ha librado de la potestad de las tinieblas, y trasladado al reino de su amado Hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 14, 'En el cual tenemos redención por su sangre, la remisión de pecados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 15, 'El cual es la imagen del Dios invisible, el primogénito de toda criatura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 16, 'Porque por él fueron criadas todas las cosas que están en los cielos, y que están en la tierra, visibles é invisibles; sean tronos, sean dominios, sean principados, sean potestades; todo fué criado por él y para él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 17, 'Y él es antes de todas las cosas, y por él todas las cosas subsisten:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 18, 'Y él es la cabeza del cuerpo que es la iglesia; él que es el principio, el primogénito de los muertos, para que en todo tenga el primado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 19, 'Por cuanto agradó al Padre que en él habitase toda plenitud,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 20, 'Y por él reconciliar todas las cosas á sí, pacificando por la sangre de su cruz, así lo que está en la tierra como lo que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 21, 'A vosotros también, que erais en otro tiempo extraños y enemigos de ánimo en malas obras, ahora empero os ha reconciliado');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 22, 'En el cuerpo de su carne por medio de muerte, para haceros santos, y sin mancha, é irreprensibles delante de él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 23, 'Si empero permanecéis fundados y firmes en la fe, y sin moveros de la esperanza del evangelio que habéis oído; el cual es predicado á toda criatura que está debajo del cielo; del cual yo Pablo soy hecho ministro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 24, 'Que ahora me gozo en lo que padezco por vosotros, y cumplo en mi carne lo que falta de las aflicciones de Cristo por su cuerpo, que es la iglesia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 25, 'De la cual soy hecho ministro, según la dispensación de Dios que me fué dada en orden á vosotros, para que cumpla la palabra de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 26, 'A saber, el misterio que había estado oculto desde los siglos y edades, mas ahora ha sido manifestado á sus santos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 27, 'A los cuales quiso Dios hacer notorias las riquezas de la gloria de este misterio entre los Gentiles; que es Cristo en vosotros la esperanza de gloria:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 28, 'El cual nosotros anunciamos, amonestando á todo hombre, y enseñando en toda sabiduría, para que presentemos á todo hombre perfecto en Cristo Jesús:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 1, 29, 'En lo cual aun trabajo, combatiendo según la operación de él, la cual obra en mí poderosamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 1, 'PORQUE quiero que sepáis cuán gran solicitud tengo por vosotros, y por los que están en Laodicea, y por todos los que nunca vieron mi rostro en carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 2, 'Para que sean confortados sus corazones, unidos en amor, y en todas riquezas de cumplido entendimiento para conocer el misterio de Dios, y del Padre, y de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 3, 'En el cual están escondidos todos los tesoros de sabiduría y conocimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 4, 'Y esto digo, para que nadie os engañe con palabras persuasivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 5, 'Porque aunque estoy ausente con el cuerpo, no obstante con el espíritu estoy con vosotros, gozándome y mirando vuestro concierto, y la firmeza de vuestra fe en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 6, 'Por tanto, de la manera que habéis recibido al Señor Jesucristo, andad en él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 7, 'Arraigados y sobreedificados en él, y confirmados en la fe, así como habéis aprendido, creciendo en ella con hacimiento de gracias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 8, 'Mirad que ninguno os engañe por filosofías y vanas sustilezas, según las tradiciones de los hombres, conforme á los elementos del mundo, y no según Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 9, 'Porque en él habita toda la plenitud de la divinidad corporalmente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 10, 'Y en él estáis cumplidos, el cual es la cabeza de todo principado y potestad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 11, 'En el cual también sois circuncidados de circuncisión no hecha con manos, con el despojamiento del cuerpo de los pecados de la carne, en la circuncisión de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 12, 'Sepultados juntamente con él en la bautismo, en el cual también resucitasteis con él, por la fe de la operación de Dios que le levantó de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 13, 'Y á vosotros, estando muertos en pecados y en la incircuncisión de vuestra carne, os vivificó juntamente con él, perdonándoos todos los pecados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 14, 'Rayendo la cédula de los ritos que nos era contraria, que era contra nosotros, quitándola de en medio y enclavándola en la cruz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 15, 'Y despojando los principados y las potestades, sacólos á la vergüenza en público, triunfando de ellos en sí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 16, 'Por tanto, nadie os juzgue en comida, ó en bebida, ó en parte de día de fiesta, ó de nueva luna, ó de sábados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 17, 'Lo cual es la sombra de lo por venir; mas el cuerpo es de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 18, 'Nadie os prive de vuestro premio, afectando humildad y culto á los ángeles, metiéndose en lo que no ha visto, vanamente hinchado en el sentido de su propia carne,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 19, 'Y no teniendo la cabeza, de la cual todo el cuerpo, alimentado y conjunto por las ligaduras y conjunturas, crece en aumento de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 20, 'Pues si sois muertos con Cristo cuanto á los rudimentos del mundo, ¿por qué como si vivieseis al mundo, os sometéis á ordenanzas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 21, 'Tales como, No manejes, ni gustes, ni aun toques,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 22, '(Las cuales cosas son todas para destrucción en el uso mismo), en conformidad á mandamientos y doctrinas de hombres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 2, 23, 'Tales cosas tienen á la verdad cierta reputación de sabiduría en culto voluntario, y humildad, y en duro trato del cuerpo; no en alguna honra para el saciar de la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 1, 'SI habéis pues resucitado con Cristo, buscad las cosas de arriba, donde está Cristo sentado á la diestra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 2, 'Poned la mira en las cosas de arriba, no en las de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 3, 'Porque muertos sois, y vuestra vida está escondida con Cristo en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 4, 'Cuando Cristo, vuestra vida, se manifestare, entonces vosotros también seréis manifestados con él en gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 5, 'Amortiguad, pues, vuestros miembros que están sobre la tierra: fornicación, inmundicia, molicie, mala concupiscencia, y avaricia, que es idolatría:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 6, 'Por las cuales cosas la ira de Dios viene sobre los hijos de rebelión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 7, 'En las cuales vosotros también anduvisteis en otro tiempo viviendo en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 8, 'Mas ahora, dejad también vosotros todas estas cosas: ira, enojo, malicia, maledicencia, torpes palabras de vuestra boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 9, 'No mintáis los unos á los otros, habiéndoos despojado del viejo hombre con sus hechos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 10, 'Y revestídoos del nuevo, el cual por el conocimiento es renovado conforme á la imagen del que lo crió;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 11, 'Donde no hay Griego ni Judío, circuncisión ni incircuncisión, bárbaro ni Scytha, siervo ni libre; mas Cristo es el todo, y en todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 12, 'Vestíos pues, como escogidos de Dios, santos y amados, de entrañas de misericordia, de benignidad, de humildad, de mansedumbre, de tolerancia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 13, 'Sufriéndoos los unos á los otros, y perdonándoos los unos á los otros si alguno tuviere queja del otro: de la manera que Crito os perdonó, así también hacedlo vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 14, 'Y sobre todas estas cosas vestíos de caridad, la cual es el vínculo de la perfección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 15, 'Y la paz de Dios gobierne en vuestros corazones, á la cual asimismo sois llamados en un cuerpo; y sed agradecidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 16, 'La palabra de Cristo habite en vosotros en abundancia en toda sabiduría, enseñándoos y exhortándoos los unos á los otros con salmos é himnos y canciones espirituales, con gracia cantando en vuestros corazones al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 17, 'Y todo lo que hacéis, sea de palabra, ó de hecho, hacedlo todo en el nombre del Señor Jesús, dando gracias á Dios Padre por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 18, 'Casadas, estad sujetas á vuestros maridos, como conviene en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 19, 'Maridos, amad á vuestras mujeres, y no seáis desapacibles con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 20, 'Hijos, obedeced á vuestros padres en todo; porque esto agrada al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 21, 'Padres, no irritéis á vuestros hijos, porque no se hagan de poco ánimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 22, 'Siervos, obedeced en todo á vuestros amos carnales, no sirviendo al ojo, como los que agradan á los hombres, sino con sencillez de corazón, temiendo á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 23, 'Y todo lo que hagáis, hacedlo de ánimo, como al Señor, y no á los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 24, 'Sabiendo que del Señor recibiréis la compensación de la herencia: porque al Señor Cristo servís.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 3, 25, 'Mas el que hace injuria, recibirá la injuria que hiciere; que no hay acepción de personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 1, 'AMOS, haced lo que es justo y derecho con vuestros siervos, sabiendo que también vosotros tenéis amo en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 2, 'Perseverad en oración, velando en ella con hacimiento de gracias:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 3, 'Orando también juntamente por nosotros, que el Señor nos abra la puerta de la palabra, para hablar el misterio de Cristo, por el cual aun estoy preso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 4, 'Para que lo manifieste como me conviene hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 5, 'Andad en sabiduría para con los extraños, redimiendo el tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 6, 'Sea vuestra palabra siempre con gracia, sazonada con sal; para que sepáis cómo os conviene responder á cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 7, 'Todos mis negocios os hará saber Tichîco, hermano amado y fiel ministro y consiervo en el Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 8, 'El cual os he enviado á esto mismo, para que entienda vuestros negocios, y consuele vuestros corazones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 9, 'Con Onésimo, amado y fiel hermano, el cual es de vosotros. Todo lo que acá pasa, os harán saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 10, 'Aristarchô, mi compañero en la prisión, os saluda, y Marcos, el sobrino de Bernabé (acerca del cual habéis recibido mandamientos; si fuere á vosotros, recibidle),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 11, 'Y Jesús, el que se llama Justo; los cuales son de la circuncisión: éstos solos son los que me ayudan en el reino de Dios, y me han sido consuelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 12, 'Os saluda Epafras, el cual es de vosotros, siervo de Cristo, siempre solícito por vosotros en oraciones, para que estéis firmes, perfectos y cumplidos en todo lo que Dios quiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 13, 'Porque le doy testimonio, que tiene gran celo por vosotros, y por los que están en Laodicea, y los que en Hierápolis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 14, 'Os saluda Lucas, el médico amado, y Demas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 15, 'Saludad á los hermanos que están en Laodicea, y á Nimfas, y á la iglesia que está en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 16, 'Y cuando esta carta fuere leída entre vosotros, haced que también sea leída en la iglesia de los Laodicenses; y la de Laodicea que la leáis también vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 17, 'Y decid á Archîpo: Mira que cumplas el ministerio que has recibido del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('COL', 'Colosenses', 4, 18, 'La salutación de mi mano, de Pablo. Acordaos de mis prisiones. La gracia sea con vosotros. Amén. enviada con Tichîco y Onésimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 1, 'PABLO, y Silvano, y Timoteo, á la iglesia de los Tesalonicenses que es en Dios Padre y en el Señor Jesucristo: Gracia y paz á vosotros de Dios nuestro Padre y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 2, 'Damos siempre gracias á Dios por todos vosotros, haciendo memoria de vosotros en nuestras oraciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 3, 'Sin cesar acordándonos delante del Dios y Padre nuestro de la obra de vuestra fe, y del trabajo de amor, y de la tolerancia de la esperanza del Señor nuestro Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 4, 'Sabiendo, hermanos amados de Dios, vuestra elección:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 5, 'Por cuanto nuestro evangelio no fué á vosotros en palabra solamente, mas también en potencia, y en Espíritu Santo, y en gran plenitud; como sabéis cuáles fuimos entre vosotros por amor de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 6, 'Y vosotros fuisteis hechos imitadores de nosotros, y del Señor, recibiendo la palabra con mucha tribulación, con gozo del Espíritu Santo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 7, 'En tal manera que habéis sido ejemplo á todos los que han creído en Macedonia y en Acaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 8, 'Porque de vosotros ha sido divulgada la palabra del Señor no sólo en Macedonia y en Acaya, mas aun en todo lugar vuestra fe en Dios se ha extendido; de modo que no tenemos necesidad de hablar nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 9, 'Porque ellos cuentan de nosotros cuál entrada tuvimos á vosotros; y cómo os convertisteis de los ídolos á Dios, para servir al Dios vivo y verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 1, 10, 'Y esperar á su Hijo de los cielos, al cual resucitó de los muertos; á Jesús, el cual nos libró de la ira que ha de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 1, 'PORQUE, hermanos, vosotros mismos sabéis que nuestra entrada á vosotros no fué vana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 2, 'Pues aun habiendo padecido antes, y sido afrentados en Filipos, como sabéis, tuvimos denuedo en Dios nuestro para anunciaros el evangelio de Dios con gran combate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 3, 'Porque nuestra exhortación no fué de error, ni de inmundicia, ni por engaño;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 4, 'Sino según fuimos aprobados de Dios para que se nos encargase el evangelio, así hablamos; no como los que agradan á los hombres, sino á Dios, el cual prueba nuestros corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 5, 'Porque nunca fuimos lisonjeros en la palabra, como sabéis, ni tocados de avaricia; Dios es testigo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 6, 'Ni buscamos de los hombres gloria, ni de vosotros, ni de otros, aunque podíamos seros carga como apóstoles de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 7, 'Antes fuimos blandos entre vosotros como la que cría, que regala á sus hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 8, 'Tan amadores de vosotros, que quisiéramos entregaros no sólo el evangelio de Dios, mas aun nuestras propias almas; porque nos erais carísimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 9, 'Porque ya, hermanos, os acordáis de nuestro trabajo y fatiga: que trabajando de noche y de día por no ser gravosos á ninguno de vosotros, os predicamos el evangelio de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 10, 'Vosotros sois testigos, y Dios, de cuán santa y justa é irreprensiblemente nos condujimos con vosotros que creísteis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 11, 'Así como sabéis de qué modo exhortábamos y consolábamos á cada uno de vosotros, como el padre á sus hijos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 12, 'Y os protestábamos que anduvieseis como es digno de Dios, que os llamó á su reino y gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 13, 'Por lo cual, también nosotros damos gracias á Dios sin cesar, de que habiendo recibido la palabra de Dios que oísteis de nosotros, recibisteis no palabra de hombres, sino según es en verdad, la palabra de Dios, el cual obra en vosotros los que creísteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 14, 'Porque vosotros, hermanos, habéis sido imitadores de las iglesias de Dios en Cristo Jesús que están en Judea; pues habéis padecido también vosotros las mismas cosas de los de vuestra propia nación, como también ellos de los Judíos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 15, 'Los cuales aun mataron al Señor Jesús y á sus propios profetas, y á nosotros nos han perseguido; y no agradan á Dios, y se oponen á todos los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 16, 'Prohibiéndonos hablar á los Gentiles, á fin de que se salven, para henchir la medida de sus pecados siempre: pues vino sobre ellos la ira hasta el extremo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 17, 'Mas nosotros, hermanos, privados de vosotros por un poco de tiempo, de vista, no de corazón, tanto más procuramos con mucho deseo ver vuestro rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 18, 'Por lo cual quisimos ir á vosotros, yo Pablo á la verdad, una vez y otra; mas Satanás nos embarazó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 19, 'Porque ¿cuál es nuestra esperanza, ó gozo, ó corona de que me gloríe? ¿No sois vosotros, delante de nuestro Señor Jesucristo en su venida?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 2, 20, 'Que vosotros sois nuestra gloria y gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 1, 'POR lo cual, no pudiendo esperar más, acordamos quedarnos solos en Atenas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 2, 'Y enviamos á Timoteo, nuestro hermano, y ministro de Dios, y colaborador nuestro en el evangelio de Cristo, á confirmaros y exhortaros en vuestra fe,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 3, 'Para que nadie se conmueva por estas tribulaciones; porque vosotros sabéis que nosotros somos puestos para esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 4, 'Que aun estando con vosotros, os predecíamos que habíamos de pasar tribulaciones, como ha acontecido y sabéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 5, 'Por lo cual, también yo, no esperando más, he enviado á reconocer vuestra fe, no sea que os haya tentado el tentador, y que nuestro trabajo haya sido en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 6, 'Empero volviendo de vosotros á nosotros Timoteo, y haciéndonos saber vuestra fe y caridad, y que siempre tenéis buena memoria de nosotros, deseando vernos, como también nosotros á vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 7, 'En ello, hermanos, recibimos consolación de vosotros en toda nuestra necesidad y aflicción por causa de vuestra fe:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 8, 'Porque ahora vivimos, si vosotros estáis firmes en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 9, 'Por lo cual, ¿qué hacimiento de gracias podremos dar á Dios por vosotros, por todo el gozo con que nos gozamos á causa de vosotros delante de nuestro Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 10, 'Orando de noche y de día con grande instancia, que veamos vuestro rostro, y que cumplamos lo que falta á vuestra fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 11, 'Mas el mismo Dios y Padre nuestro, y el Señor nuestro Jesucristo, encamine nuestro viaje á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 12, 'Y á vosotros multiplique el Señor, y haga abundar el amor entre vosotros, y para con todos, como es también de nosotros para con vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 3, 13, 'Para que sean confirmados vuestros corazones en santidad, irreprensibles delante de Dios y nuestro Padre, para la venida de nuestro Señor Jesucristo con todos sus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 1, 'RESTA pues, hermanos, que os roguemos y exhortemos en el Señor Jesús, que de la manera que fuisteis enseñados de nosotros de cómo os conviene andar, y agradar á Dios, así vayáis creciendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 2, 'Porque ya sabéis qué mandamientos os dimos por el Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 3, 'Porque la voluntad de Dios es vuestra santificación: que os apartéis de fornicación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 4, 'Que cada uno de vosotros sepa tener su vaso en santificación y honor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 5, 'No con afecto de concupiscencia, como los Gentiles que no conocen á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 6, 'Que ninguno oprima, ni engañe en nada á su hermano: porque el Señor es vengador de todo esto, como ya os hemos dicho y protestado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 7, 'Porque no nos ha llamado Dios á inmundicia, sino á santificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 8, 'Así que, el que menosprecia, no menosprecia á hombre, sino á Dios, el cual también nos dió su Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 9, 'Mas acerca de la caridad fraterna no habéis menester que os escriba: porque vosotros mismos habéis aprendido de Dios que os améis los unos á los otros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 10, 'Y también lo hacéis así con todos los hermanos que están por toda Macedonia. Empero os rogamos, hermanos, que abundéis más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 11, 'Y que procuréis tener quietud, y hacer vuestros negocios, y obréis de vuestras manos de la manera que os hemos mandado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 12, 'A fin de que andéis honestamente para con los extraños, y no necesitéis de nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 13, 'Tampoco, hermanos, queremos que ignoréis acerca de los que duermen, que no os entristezcáis como los otros que no tienen esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 14, 'Porque si creemos que Jesús murió y resucitó, así también traerá Dios con él á los que durmieron en Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 15, 'Por lo cual, os decimos esto en palabra del Señor: que nosotros que vivimos, que habremos quedado hasta la venida del Señor, no seremos delanteros á los que durmieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 16, 'Porque el mismo Señor con aclamación, con voz de arcángel, y con trompeta de Dios, descenderá del cielo; y los muertos en Cristo resucitarán primero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 17, 'Luego nosotros, los que vivimos, los que quedamos, juntamente con ellos seremos arrebatados en las nubes á recibir al Señor en el aire, y así estaremos siempre con el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 4, 18, 'Por tanto, consolaos los unos á los otros en estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 1, 'EMPERO acerca de los tiempos y de los momentos, no tenéis, hermanos, necesidad de que yo os escriba:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 2, 'Porque vosotros sabéis bien, que el día del Señor vendrá así como ladrón de noche,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 3, 'Que cuando dirán, Paz y seguridad, entonces vendrá sobre ellos destrucción de repente, como los dolores á la mujer preñada; y no escaparán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 4, 'Mas vosotros, hermanos, no estáis en tinieblas, para que aquel día os sobrecoja como ladrón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 5, 'Porque todos vosotros sois hijos de luz, é hijos del día; no somos de la noche, ni de las tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 6, 'Por tanto, no durmamos como los demás; antes velemos y seamos sobrios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 7, 'Porque los que duermen, de noche duermen; y los que están borrachos, de noche están borrachos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 8, 'Mas nosotros, que somos del día, estemos sobrios, vestidos de cota de fe y de caridad, y la esperanza de salud por yelmo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 9, 'Porque no nos ha puesto Dios para ira, sino para alcanzar salud por nuestro Señor Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 10, 'El cual murió por nosotros, para que ó que velemos, ó que durmamos, vivamos juntamente con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 11, 'Por lo cual, consolaos los unos á los otros, y edificaos los unos á los otros, así como lo hacéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 12, 'Y os rogamos, hermanos, que reconozcáis á los que trabajan entre vosotros, y os presiden en el Señor, y os amonestan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 13, 'Y que los tengáis en mucha estima por amor de su obra. Tened paz los unos con los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 14, 'También os rogamos, hermanos, que amonestéis á los que andan desordenadamente, que consoléis á los de poco ánimo, que soportéis á los flacos, que seáis sufridos para con todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 15, 'Mirad que ninguno dé á otro mal por mal; antes seguid lo bueno siempre los unos para con los otros, y para con todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 16, 'Estad siempre gozosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 17, 'Orad sin cesar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 18, 'Dad gracias en todo; porque esta es la voluntad de Dios para con vosotros en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 19, 'No apaguéis el Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 20, 'No menospreciéis las profecías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 21, 'Examinadlo todo; retened lo bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 22, 'Apartaos de toda especie de mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 23, 'Y el Dios de paz os santifique en todo; para que vuestro espíritu y alma y cuerpo sea guardado entero sin reprensión para la venida de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 24, 'Fiel es el que os ha llamado; el cual también lo hará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 25, 'Hermanos, orad por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 26, 'Saludad á todos los hermanos en ósculo santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 27, 'Conjúroos por el Señor, que esta carta sea leída á todos los santos hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TH', '1 Tesalonicenses', 5, 28, 'La gracia de nuestro Señor Jesucristo sea con vosotros. Amén. espístola á los Tesalonicenses fué escrita de Atenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 1, 'PABLO, y Silvano, y Timoteo, á la iglesia de los Tesalonicenses que es en Dios nuestro Padre y en el Señor Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 2, 'Gracia y paz á vosotros de Dios nuestro Padre y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 3, 'Debemos siempre dar gracias á Dios de vosotros, hermanos, como es digno, por cuanto vuestra fe va creciendo, y la caridad de cada uno de todos vosotros abunda entre vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 4, 'Tanto, que nosotros mismos nos gloriamos de vosotros en las iglesias de Dios, de vuestra paciencia y en todas vuestras persecuciones y tribulaciones que sufrís:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 5, 'Una demostración del justo juicio de Dios, para que seáis tenidos por dignos del reino de Dios, por el cual asimismo padecéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 6, 'Porque es justo para con Dios pagar con tribulación á los que os atribulan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 7, 'Y á vosotros, que sois atribulados, dar reposo con nosotros, cuando se manifestará el Señor Jesús del cielo con los ángeles de su potencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 8, 'En llama de fuego, para dar el pago á los que no conocieron á Dios, ni obedecen al evangelio de nuestro Señor Jesucristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 9, 'Los cuales serán castigados de eterna perdición por la presencia del Señor, y por la gloria de su potencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 10, 'Cuando viniere para ser glorificado en sus santos, y á hacerse admirable en aquel día en todos los que creyeron: (por cuanto nuestro testimonio ha sido creído entre vosotros.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 11, 'Por lo cual, asimismo oramos siempre por vosotros, que nuestro Dios os tenga por dignos de su vocación, e hincha de bondad todo buen intento, y toda obra de fe con potencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 1, 12, 'Para que el nombre, de nuestro Señor Jesucristo sea glorificado en vosotros, y vosotros en él, por la gracia de nuestro Dios y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 1, 'EMPERO os rogamos, hermanos, cuanto á la venida de nuestro Señor Jesucristo, y nuestro recogimiento á él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 2, 'Que no os mováis fácilmente de vuestro sentimiento, ni os conturbéis ni por espíritu, ni por palabra, ni por carta como nuestra, como que el día del Señor esté cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 3, 'No os engañe nadie en ninguna manera; porque no vendrá sin que venga antes la apostasía, y se manifieste el hombre de pecado, el hijo de perdición,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 4, 'Oponiéndose, y levantándose contra todo lo que se llama Dios, ó que se adora; tanto que se asiente en el templo de Dios como Dios, haciéndose parecer Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 5, '¿No os acordáis que cuando estaba todavía con vosotros, os decía esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 6, 'Y ahora vosotros sabéis lo que impide, para que á su tiempo se manifieste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 7, 'Porque ya está obrando el misterio de iniquidad: solamente espera hasta que sea quitado de en medio el que ahora impide;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 8, 'Y entonces será manifestado aquel inicuo, al cual el Señor matará con el espíritu de su boca, y destruirá con el resplandor de su venida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 9, 'A aquel inicuo, cuyo advenimiento es según operación de Satanás, con grande potencia, y señales, y milagros mentirosos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 10, 'Y con todo engaño de iniquidad en los que perecen; por cuanto no recibieron el amor de la verdad para ser salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 11, 'Por tanto, pues, les envía Dios operación de error, para que crean á la mentira;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 12, 'Para que sean condenados todos los que no creyeron á la verdad, antes consintieron á la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 13, 'Mas nosotros debemos dar siempre gracias á Dios por vosotros, hermanos amados del Señor, de que Dios os haya escogido desde el principio para salud, por la santificación del Espíritu y fe de la verdad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 14, 'A lo cual os llamó por nuestro evangelio, para alcanzar la gloria de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 15, 'Así que, hermanos, estad firmes, y retened la doctrina que habéis aprendido, sea por palabra, ó por carta nuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 16, 'Y el mismo Señor nuestro Jesucristo, y Dios y Padre nuestro, el cual nos amó, y nos dió consolación eterna, y buena esperanza por gracia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 2, 17, 'Consuele vuestros corazones, y os confirme en toda buena palabra y obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 1, 'RESTA, hermanos, que oréis por nosotros, que la palabra del Señor corra y sea glorificada así como entre vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 2, 'Y que seamos librados de hombres importunos y malos; porque no es de todos la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 3, 'Mas fiel es el Señor, que os confirmará y guardará del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 4, 'Y tenemos confianza de vosotros en el Señor, que hacéis y haréis lo que os hemos mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 5, 'Y el Señor enderece vuestros corazones en el amor de Dios, y en la paciencia de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 6, 'Empero os denunciamos, hermanos, en el nombre de nuestro Señor Jesucristo, que os apartéis de todo hermano que anduviere fuera de orden, y no conforme á la doctrina que recibieron de nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 7, 'Porque vosotros mismos sabéis de qué manera debéis imitarnos: porque no anduvimos desordenadamente entre vosotros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 8, 'Ni comimos el pan de ninguno de balde; antes, obrando con trabajo y fatiga de noche y de día, por no ser gravosos á ninguno de vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 9, 'No porque no tuviésemos potestad, sino por daros en nosotros un dechado, para que nos imitaseis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 10, 'Porque aun estando con vosotros, os denunciábamos esto: Que si alguno no quisiere trabajar, tampoco coma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 11, 'Porque oímos que andan algunos entre vosotros fuera de orden, no trabajando en nada, sino ocupados en curiosear.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 12, 'Y á los tales requerimos y rogamos por nuestro Señor Jesucristo, que, trabajando con reposo, coman su pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 13, 'Y vosotros, hermanos, no os canséis de hacer bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 14, 'Y si alguno no obedeciere á nuestra palabra por carta, notad al tal, y no os juntéis con él, para que se avergüence.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 15, 'Mas no lo tengáis como á enemigo, sino amonestadle como á hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 16, 'Y el mismo Señor de paz os dé siempre paz en toda manera. El Señor sea con todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 17, 'Salud de mi mano, Pablo, que es mi signo en toda carta mía: así escribo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TH', '2 Tesalonicenses', 3, 18, 'La gracia de nuestro Señor Jesucristo sea con todos vosotros. Amén. Epístola á los Tesalonicenses fué escrita de Atenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 1, 'PABLO, apóstol de Jesucristo por la ordenación de Dios nuestro Salvador, y del Señor Jesucristo, nuestra esperanza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 2, 'A Timoteo, verdadero hijo en la fe: Gracia, misericordia y paz de Dios nuestro Padre, y de Cristo Jesús nuestro Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 3, 'Como te rogué que te quedases en Efeso, cuando partí para Macedonia, para que requirieses á algunos que no enseñen diversa doctrina,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 4, 'Ni presten atención á fábulas y genealogías sin término, que antes engendran cuestiones que la edificación de Dios que es por fe; así te encargo ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 5, 'Pues el fin del mandamiento es la caridad nacida de corazón limpio, y de buena conciencia, y de fe no fingida:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 6, 'De lo cual distrayéndose algunos, se apartaron á vanas pláticas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 7, 'Queriendo ser doctores de la ley, sin entender ni lo que hablan, ni lo que afirman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 8, 'Sabemos empero que la ley es buena, si alguno usa de ella legítimamente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 9, 'Conociendo esto, que la ley no es puesta para el justo, sino para los injustos y para los desobedientes, para los impíos y pecadores, para los malos y profanos, para los parricidas y matricidas, para los homicidas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 10, 'Para los fornicarios, para los sodomitas, para los ladrones de hombres, para los mentirosos y ladrones de hombres, para los mentirosos y fjperjuros, y si hay alguna otra cosa contraria á la sana doctrina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 11, 'Según el evangelio de la gloria del Dios bendito, el cual á mí me ha sido encargado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 12, 'Y doy gracias al que me fortificó, á Cristo Jesús nuestro Señor, de que me tuvo por fiel, poniéndome en el ministerio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 13, 'Habiendo sido antes blasfemo y perseguidor é injuriador: mas fuí recibido á misericordia, porque lo hice con ignorancia en incredulidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 14, 'Mas la gracia de nuestro Señor fué más abundante con la fe y amor que es en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 15, 'Palabra fiel y digna de ser recibida de todos: que Cristo Jesús vino al mundo para salvar á los pecadores, de los cuales yo soy el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 16, 'Mas por esto fuí recibido á misericordia, para que Jesucristo mostrase en mí el primero toda su clemencia, para ejemplo de los que habían de creer en él para vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 17, 'Por tanto, al Rey de siglos, inmortal, invisible, al solo sabio Dios sea honor y gloria por los siglos de los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 18, 'Este mandamiento, hijo Timoteo, te encargo, para que, conforme á las profecías pasadas de ti, milites por ellas buena milicia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 19, 'Manteniendo la fe y buena conciencia, la cual echando de sí algunos, hicieron naufragio en la fe:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 1, 20, 'De los cuales son Himeneo y Alejandro, los cuales entregué á Satanás, para que aprendan á no blasfemar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 1, 'AMONESTO pues, ante todas cosas, que se hagan rogativas, oraciones, peticiones, hacimientos de gracias, por todos los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 2, 'Por los reyes y por todos los que están en eminencia, para que vivamos quieta y reposadamente en toda piedad y honestidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 3, 'Porque esto es bueno y agradable delante de Dios nuestro Salvador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 4, 'El cual quiere que todos los hombres sean salvos, y que vengan al conocimiento de la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 5, 'Porque hay un Dios, asimismo un mediador entre Dios y los hombres, Jesucristo hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 6, 'El cual se dió á sí mismo en precio del rescate por todos, para testimonio en sus tiempos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 7, 'De lo que yo soy puesto por predicador y apóstol, (digo verdad en Cristo, no miento) doctor de los Gentiles en fidelidad y verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 8, 'Quiero, pues, que los hombres oren en todo lugar, levantando manos limpias, sin ira ni contienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 9, 'Asimismo también las mujeres, ataviándose en hábito honesto, con vergüenza y modestia; no con cabellos encrespados, u oro, ó perlas, ó vestidos costosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 10, 'Sino de buenas obras, como conviene á mujeres que profesan piedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 11, 'La mujer aprenda en silencio, con toda sujeción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 12, 'Porque no permito á la mujer enseñar, ni tomar autoridad sobre el hombre, sino estar en silencio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 13, 'Porque Adam fué formado el primero, después Eva;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 14, 'Y Adam no fué engañado, sino la mujer, siendo seducida, vino á ser envuelta en transgresión:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 2, 15, 'Empero se salvará engendrando hijos, si permaneciere en la fe y caridad y santidad, con modestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 1, 'PALABRA fiel: Si alguno apetece obispado, buena obra desea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 2, 'Conviene, pues, que el obispo sea irreprensible, marido de una mujer, solícito, templado, compuesto, hospedador, apto para enseñar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 3, 'No amador del vino, no heridor, no codicioso de torpes ganancias, sino moderado, no litigioso, ajeno de avaricia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 4, 'Que gobierne bien su casa, que tenga sus hijos en sujeción con toda honestidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 5, '(Porque el que no sabe gobernar su casa, ¿cómo cuidará de la iglesia de Dios?)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 6, 'No un neófito, porque inflándose no caiga en juicio del diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 7, 'También conviene que tenga buen testimonio de los extraños, porque no caiga en afrenta y en lazo del diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 8, 'Los diáconos asimismo, deben ser honestos, no bilingües, no dados á mucho vino, no amadores de torpes ganancias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 9, 'Que tengan el misterio de la fe con limpia conciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 10, 'Y éstos también sean antes probados; y así ministren, si fueren sin crimen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 11, 'Las mujeres asimismo, honestas, no detractoras, templadas, fieles en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 12, 'Los diáconos sean maridos de una mujer, que gobiernen bien sus hijos y sus casas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 13, 'Porque los que bien ministraren, ganan para sí buen grado, y mucha confianza en la fe que es en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 14, 'Esto te escribo con esperanza que iré presto á ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 15, 'Y si no fuere tan presto, para que sepas cómo te conviene conversar en la casa de Dios, que es la iglesia del Dios vivo, columna y apoyo de la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 3, 16, 'Y sin cotradicción, grande es el misterio de la piedad: Dios ha sido manifestado en carne; ha sido justificado con el Espíritu; ha sido visto de los ángeles; ha sido predicado á los Gentiles; ha sido creído en el mundo; ha sido recibido en gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 1, 'EMPERO el Espíritu dice manifiestamente, que en los venideros tiempos alguno apostatarán de la fe escuchando á espíritus de error y á doctrinas de demonios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 2, 'Que con hipocresía hablarán mentira, teniendo cauterizada la conciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 3, 'Que prohibirán casarse, y mandarán abstenerse de las viandas que Dios crió para que con hacimiento de gracias participasen de ellas los fieles, y los que han conocido la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 4, 'Porque todo lo que Dios crió es bueno, y nada hay que desechar, tomándose con hacimiento de gracias:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 5, 'Porque por la palabra de Dios y por la oración es santificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 6, 'Si esto propusieres á los hermanos, serás buen ministro de Jesucristo, criado en las palabras de la fe y de la buena doctrina, la cual has alcanzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 7, 'Mas las fábulas profanas y de viejas desecha, y ejercítate para la piedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 8, 'Porque el ejercicio corporal para poco es provechoso; mas la piedad para todo aprovecha, pues tiene promesa de esta vida presente, y de la venidera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 9, 'Palabra fiel es esta, y digna de ser recibida de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 10, 'Que por esto aun trabajamos y sufrimos oprobios, porque esperamos en el Dios viviente, el cual es Salvador de todos los hombres, mayormente de los que creen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 11, 'Esto manda y enseña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 12, 'Ninguno tenga en poco tu juventud; pero sé ejemplo de los fieles en palabra, en conversación, en caridad, en espíritu, en fe, en limpieza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 13, 'Entre tanto que voy, ocúpate en leer, en exhortar, en enseñar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 14, 'No descuides el don que está en ti, que te es dado por profecía con la imposición de las manos del presbiterio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 15, 'Medita estas cosas; ocúpate en ellas; para que tu aprovechamiento sea manifiesto á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 4, 16, 'Ten cuidado de ti mismo y de la doctrina; persiste en ello; pues haciendo esto, á ti mismo salvarás y á los que te oyeren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 1, 'NO reprendas al anciano, sino exhórtale como á padre: á los más jóvenes, como á hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 2, 'A las ancianas, como á madres; á las jovencitas, como á hermanas, con toda pureza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 3, 'Honra á las viudas que en verdad son viudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 4, 'Pero si alguna viuda tuviere hijos, ó nietos, aprendan primero á gobernar su casa piadosamente, y á recompensar á sus padres: porque esto es lo honesto y agradable delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 5, 'Ahora, la que en verdad es viuda y solitaria, espera en Dios, y es diligente en suplicaciones y oraciones noche y día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 6, 'Pero la que vive en delicias, viviendo está muerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 7, 'Denuncia pues estas cosas, para que sean sin reprensión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 8, 'Y si alguno no tiene cuidado de los suyos, y mayormente de los de su casa, la fe negó, y es peor que un infiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 9, 'La viuda sea puesta en clase especial, no menos que de sesenta años, que haya sido esposa de un solo marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 10, 'Que tenga testimonio en buenas obras; si crió hijos; si ha ejercitado la hospitalidad; si ha lavado los pies de los santos; si ha socorrido á los afligidos; si ha seguido toda buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 11, 'Pero viudas más jóvenes no admitas: porque después de hacerse licenciosas contra Cristo, quieren casarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 12, 'Condenadas ya, por haber falseado la primera fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 13, 'Y aun también se acostrumbran á ser ociosas, á andar de casa en casa; y no solamente ociosas, sino también parleras y curiosas, hablando lo que no conviene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 14, 'Quiero pues, que las que son jóvenes se casen, críen hijos, gobiernen la casa; que ninguna ocasión den al adversario para maldecir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 15, 'Porque ya algunas han vuelto atrás en pos de Satanás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 16, 'Si algún fiel ó alguna fiel tiene viudas, manténgalas, y no sea gravada la iglesia; á fin de que haya lo suficiente para las que de verdad son viudas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 17, 'Los ancianos que gobiernan bien, sean tenidos por dignos de doblada honra; mayormente los que trabajan en predicar y enseñar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 18, 'Porque la Escritura dice: No embozarás al buey que trilla; y: Digno es el obrero de su jornal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 19, 'Contra el anciano no recibas acusación sino con dos ó tres testigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 20, 'A los que pecaren, repréndelos delante de todos, para que los otros también teman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 21, 'Te requiero delante de Dios y del Señor Jesucristo, y de sus ángeles escogidos, que guardes estas cosas sin perjuicio de nadie, que nada hagas inclinándote á la una parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 22, 'No impongas de ligero las manos á ninguno, ni comuniques en pecados ajenos: consérvate en limpieza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 23, 'No bebas de aquí adelante agua, sino usa de un poco de vino por causa del estómago, y de tus continuas enfermedades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 24, 'Los pecados de algunos hombres, antes que vengan ellos á juicio, son manifiestos; mas á otros les vienen después.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 5, 25, 'Asimismo las buenas obras antes son manifiestas; y las que son de otra manera, no pueden esconderse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 1, 'TODOS los que están debajo del yugo de servidumbre, tengan á sus señores por dignos de toda honra, porque no sea blasfemado el nombre del Señor y la doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 2, 'Y los que tienen amos fieles, no los tengan en menos, por ser hermanos; antes sírvanles mejor, por cuanto son fieles y amados, y partícipes del beneficio. Esto enseña y exhorta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 3, 'Si alguno enseña otra cosa, y no asiente á sanas palabras de nuestro Señor Jesucristo, y á la doctrina que es conforme á la piedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 4, 'Es hinchado, nada sabe, y enloquece acerca de cuestiones y contiendas de palabras, de las cuales nacen envidias, pleitos, maledicencias, malas sospechas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 5, 'Porfías de hombres corruptos de entendimiento y privados de la verdad, que tienen la piedad por granjería: apártate de los tales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 6, 'Empero grande granjería es la piedad con contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 7, 'Porque nada hemos traído á este mundo, y sin duda nada podremos sacar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 8, 'Así que, teniendo sustento y con qué cubrirnos, seamos contentos con esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 9, 'Porque los que quieren enriquecerse, caen en tentación y lazo, y en muchas codicias locas y dañosas, que hunden á los hombres en perdición y muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 10, 'Porque el amor del dinero es la raíz de todos los males: el cual codiciando algunos, se descaminaron de la fe, y fueron traspasados de muchos dolores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 11, 'Mas tú, oh hombre de Dios, huye de estas cosas, y sigue la justicia, la piedad, la fe, la caridad, la paciencia, la mansedumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 12, 'Pelea la buena batalla de la fe, echa mano de la vida eterna, á la cual asimismo eres llamado, habiendo hecho buena profesión delante de muchos testigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 13, 'Te mando delante de Dios, que da vida á todas las cosas, y de Jesucristo, que testificó la buena profesión delante de Poncio Pilato,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 14, 'Que guardes el mandamiento sin mácula ni reprensión, hasta la aparición de nuestro Señor Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 15, 'La cual á su tiempo mostrará el Bienaventurado y solo Poderoso, Rey de reyes, y Señor de señores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 16, 'Quien sólo tiene inmortalidad, que habita en luz inaccesible; á quien ninguno de los hombres ha visto ni puede ver: al cual sea la honra y el imperio sempiterno. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 17, 'A los ricos de este siglo manda que no sean altivos, ni pongan la esperanza en la incertidumbre de las riquezas, sino en el Dios vivo, que nos da todas las cosas en abundancia de que gocemos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 18, 'Que hagan bien, que sean ricos en buenas obras, dadivosos, que con facilidad comuniquen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 19, 'Atesorando para sí buen fundamento para lo por venir, que echen mano á la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 20, 'Oh Timoteo, guarda lo que se te ha encomendado, evitando las profanas pláticas de vanas cosas, y los argumentos de la falsamente llamada ciencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1TI', '1 Timoteo', 6, 21, 'La cual profesando algunos, fueron descaminados acerca de la fe. La gracia sea contigo. Amén. espístola á Timoteo fué escrita de Laodicea, que es metrópoli de la Frigia Pacatiana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 1, 'PABLO, apóstol de Jesucristo por la voluntad de Dios, según la promesa de la vida que es en Cristo Jesús,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 2, 'A Timoteo, amado hijo: Gracia, misericordia, y paz de Dios el Padre y de Jesucristo nuestro Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 3, 'Doy gracias á Dios, al cual sirvo desde mis mayores con limpia conciencia, de que sin cesar tengo memoria de ti en mis oraciones noche y día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 4, 'Deseando verte, acordándome de tus lágrimas, para ser lleno de gozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 5, 'Trayendo á la memoria la fe no fingida que hay en ti, la cual residió primero en tu abuela Loida, y en tu madre Eunice; y estoy cierto que en ti también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 6, 'Por lo cual te aconsejo que despiertes el don de Dios, que está en ti por la imposición de mis manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 7, 'Porque no nos ha dado Dios el espíritu de temor, sino el de fortaleza, y de amor, y de templanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 8, 'Por tanto no te avergüences del testimonio de nuestro Señor, ni de mí, preso suyo; antes sé participante de los trabajos del evangelio según la virtud de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 9, 'Que nos salvó y llamó con vocación santa, no conforme á nuestras obras, mas según el intento suyo y gracia, la cual nos es dada en Cristo Jesús antes de los tiempos de los siglos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 10, 'Mas ahora es manifestada por la aparición de nuestro Salvador Jesucristo, el cual quitó la muerte, y sacó á la luz la vida y la inmortalidad por el evangelio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 11, 'Del cual yo soy puesto predicador, y apóstol, y maestro de los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 12, 'Por lo cual asimismo padezco esto: mas no me avergüenzo; porque yo sé á quien he creído, y estoy cierto que es poderoso para guardar mi depósito para aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 13, 'Retén la forma de las sanas palabras que de mi oíste, en la fe y amor que es en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 14, 'Guarda el buen depósito por el Espíritu Santo que habita en nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 15, 'Ya sabes esto, que me han sido contrarios todos los que son en Asia, de los cuales son Figello y Hermógenes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 16, 'Dé el Señor misericordia á la casa de Onesíforo; que muchas veces me refrigeró, y no se avergonzó de mi cadena:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 17, 'Antes, estando él en Roma, me buscó solícitamente, y me halló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 1, 18, 'Déle el Señor que halle misericordia cerca del Señor en aquel día. Y cuánto nos ayudó en Efeso, tú lo sabes mejor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 1, 'PUES tú, hijo mío, esfuérzate en la gracia que es en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 2, 'Y lo que has oído de mí entre muchos testigos, esto encarga á los hombres fieles que serán idóneos para enseñar también á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 3, 'Tú pues, sufre trabajos como fiel soldado de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 4, 'Ninguno que milita se embaraza en los negocios de la vida; á fin de agradar á aquel que lo tomó por soldado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 5, 'Y aun también el que lidia, no es coronado si no lidiare legítimamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 6, 'El labrador, para recibir los frutos, es menester que trabaje primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 7, 'Considera lo que digo; y el Señor te dé entendimiento en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 8, 'Acuérdate que Jesucristo, el cual fué de la simiente de David, resucitó de los muertos conforme á mi evangelio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 9, 'En el que sufro trabajo, hasta las prisiones á modo de malhechor; mas la palabra de Dios no está presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 10, 'Por tanto, todo lo sufro por amor de los escogidos, para que ellos también consigan la salud que es en Cristo Jesús con gloria eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 11, 'Es palabra fiel: Que si somos muertos con él, también viviremos con él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 12, 'Si sufrimos, también reinaremos con él: si negáremos, él también nos negará:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 13, 'Si fuéremos infieles, él permanece fiel: no se puede negar á sí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 14, 'Recuérdales esto, protestando delante del Señor que no contiendan en palabras, lo cual para nada aprovecha, antes trastorna á los oyentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 15, 'Procura con diligencia presentarte á Dios aprobado, como obrero que no tiene de qué avergonzarse, que traza bien la palabra de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 16, 'Mas evita profanas y vanas parlerías; porque muy adelante irán en la impiedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 17, 'Y la palabra de ellos carcomerá como gangrena: de los cuales es Himeneo y Fileto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 18, 'Que se han descaminado de la verdad, diciendo que la resurrección es ya hecha, y trastornan la fe de algunos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 19, 'Pero el fundamento de Dios está firme, teniendo este sello: Conoce el Señor á los que son suyos; y: Apártese de iniquidad todo aquel que invoca el nombre de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 20, 'Mas en una casa grande, no solamente hay vasos de oro y de plata, sino también de madera y de barro: y asimismo unos para honra, y otros para deshonra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 21, 'Así que, si alguno se limpiare de estas cosas, será vaso para honra, santificado, y útil para los usos del Señor, y aparejado para todo buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 22, 'Huye también los deseos juveniles; y sigue la justicia, la fe, la caridad, la paz, con los que invocan al Señor de puro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 23, 'Empero las cuestiones necias y sin sabiduría desecha, sabiendo que engendran contiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 24, 'Que el siervo del Señor no debe ser litigioso, sino manso para con todos, apto para enseñar, sufrido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 25, 'Que con mansedumbre corrija á los que se oponen: si quizá Dios les dé que se arrepientan para conocer la verdad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 2, 26, 'Y se zafen del lazo del diablo, en que están cuativos á voluntad de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 1, 'ESTO también sepas, que en los postreros días vendrán tiempos peligrosos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 2, 'Que habrá hombres amadores de sí mismos, avaros, vanagloriosos, soberbios, detractores, desobedientes á los padres, ingratos, sin santidad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 3, 'Sin afecto, desleales, calumniadores, destemplados, crueles, aborrecedores de lo bueno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 4, 'Traidores, arrebatados, hinchados, amadores de los deleites más que de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 5, 'Teniendo apariencia de piedad, mas habiendo negado la eficacia de ella: y á éstos evita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 6, 'Porque de éstos son los que se entran por las casas, y llevan cautivas las mujercillas cargadas de pecados, llevadas de diversas concupiscencias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 7, 'Que siempre aprenden, y nunca pueden acabar de llegar al conocimiento de la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 8, 'Y de la manera que Jannes y Jambres resistieron á Moisés, así también estos resisten á la verdad; hombres corruptos de entendimiento, réprobos acerca de la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 9, 'Mas no prevalecerán; porque su insensatez será manifiesta á todos, como también lo fué la de aquéllos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 10, 'Pero tú has comprendido mi doctrina, instrucción, intento, fe, largura de ánimo, caridad, paciencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 11, 'Persecuciones, aflicciones, cuales me sobrevinieron en Antioquía, en Iconio, en Listra, cuales persecuciones he sufrido; y de todas me ha librado el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 12, 'Y también todos los que quieren vivir píamente en Cristo Jesús, padecerán persecución.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 13, 'Mas los malos hombres y los engañadores, irán de mal en peor, engañando y siendo engañados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 14, 'Empero persiste tú en lo que has aprendido y te persuadiste, sabiendo de quién has aprendido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 15, 'Y que desde la niñez has sabido las Sagradas Escrituras, las cuales te pueden hacer sabio para la salud por la fe que es en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 16, 'Toda Escritura es inspirada divinamente y útil para enseñar, para redargüir, para corregir, para instituir en justicia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 3, 17, 'Para que el hombre de Dios sea perfecto, enteramente instruído para toda buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 1, 'REQUIERO yo pues delante de Dios, y del Señor Jesucristo, que ha de juzgar á los vivos y los muertos en su manifestación y en su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 2, 'Que prediques la palabra; que instes á tiempo y fuera de tiempo; redarguye, reprende; exhorta con toda paciencia y doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 3, 'Porque vendrá tiempo cuando ni sufrirán la sana doctrina; antes, teniendo comezón de oir, se amotonarán maestros conforme á sus concupiscencias,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 4, 'Y apartarán de la verdad el oído y se volverán á las fábulas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 5, 'Pero tú vela en todo, soporta las aflicciones, haz la obra de evangelista, cumple tu ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 6, 'Porque yo ya estoy para ser ofrecido, y el tiempo de mi partida está cercano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 7, 'He peleado la buena batalla, he acabado la carrera, he guardado la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 8, 'Por lo demás, me está guardada la corona de justicia, la cual me dará el Señor, juez justo, en aquel día; y no sólo á mí, sino también á todos los que aman su venida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 9, 'Procura venir presto á mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 10, 'Porque Demas me ha desamparado, amando este siglo, y se ha ido á Tesalónica; Crescente á Galacia, Tito á Dalmacia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 11, 'Lucas solo está conmigo. Toma á Marcos, y traéle contigo; porque me es útil para el ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 12, 'A Tychîco envié á Efeso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 13, 'Trae, cuando vinieres, el capote que dejé en Troas en casa de Carpo: y los libros, mayormente los pergaminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 14, 'Alejandro el calderero me ha causado muchos males: el Señor le pague conforme á sus hechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 15, 'Guárdate tú también de él; que en grande manera ha resistido á nuestras palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 16, 'En mi primera defensa ninguno me ayudó, antes me desampararon todos: no les sea imputado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 17, 'Mas el Señor me ayudó, y me esforzó para que por mí fuese cumplida la predicación, y todos los Gentiles oyesen; y fuí librado de la boca del león.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 18, 'Y el Señor me librará de toda obra mala, y me preservará para su reino celestial: al cual sea gloria por los siglos de los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 19, 'Saluda á Prisca y á Aquila, y á la casa de Onesíforo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 20, 'Erasto se quedó en Corinto; y á Trófimo dejé en Mileto enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 21, 'Procura venir antes del invierno. Eubulo te saluda, y Pudente, y Lino, y Claudia, y todos los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2TI', '2 Timoteo', 4, 22, 'El Señor Jesucristo sea con tu espíritu. La gracia sea con vosotros. Amén. epístola á Timoteo, el cual fué el primer obispo ordenado en Efeso, fué escrita de Roma, cuando Pablo fué presentado la segunda vez á César Nerón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 1, 'PABLO, siervo de Dios, y apóstol de Jesucristo, según la fe de los escogidos de Dios, y el conocimiento de la verdad que es según la piedad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 2, 'Para la esperanza de la vida eterna, la cual Dios, que no puede mentir, prometió antes de los tiempos de los siglos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 3, 'Y manifestó á sus tiempos su palabra por la predicación, que me es á mí encomendada por mandamiento de nuestro Salvador Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 4, 'A Tito, verdadero hijo en la común fe: Gracia, misericordia, y paz de Dios Padre, y del Señor Jesucristo Salvador nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 5, 'Por esta causa te dejé en Creta, para que corrigieses lo que falta, y pusieses ancianos por las villas, así como yo te mandé:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 6, 'El que fuere sin crimen, marido de una mujer, que tenga hijos fieles que no estén acusados de disolución, ó contumaces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 7, 'Porque es menester que el obispo sea sin crimen, como dispensador de Dios; no soberbio, no iracundo, no amador del vino, no heridor, no codicioso de torpes ganancias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 8, 'Sino hospedador, amador de lo bueno, templado, justo, santo, continente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 9, 'Retenedor de la fiel palabra que es conforme á la doctrina: para que también pueda exhortar con sana doctrina, y convencer á los que contradijeren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 10, 'Porque hay aún muchos contumaces, habladores de vanidades, y engañadores de las almas, mayormente los que son de la circuncisión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 11, 'A los cuales es preciso tapar la boca; que trastornan casas enteras; enseñando lo que no conviene, por torpe ganancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 12, 'Dijo uno de ellos, propio profeta de ellos: Los Cretenses, siempre mentirosos, malas bestias, vientres perezosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 13, 'Este testimonio es verdadero: por tanto, repréndelos duramente, para que sean sanos en la fe,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 14, 'No atendiendo á fábulas judaicas, y á mandamientos de hombres que se apartan de la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 15, 'Todas las cosas son limpias á los limpios; mas á los contaminados é infieles nada es limpio: antes su alma y conciencia están contaminadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 1, 16, 'Profésanse conocer á Dios; mas con los hechos lo niegan, siendo abominables y rebeldes, reprobados para toda buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 1, 'EMPERO tú, habla lo que conviene á la sana doctrina:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 2, 'Que los viejos sean templados, graves, prudentes, sanos en la fe, en la caridad, en la paciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 3, 'Las viejas, asimismo, se distingan en un porte santo; no calumniadoras, no dadas á mucho vino, maestras de honestidad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 4, 'Que enseñen á las mujeres jóvenes á ser predentes, á que amen á sus maridos, á que amen á sus hijos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 5, 'A ser templadas, castas, que tengan cuidado de la casa, buenas, sujetas á sus maridos: porque la palabra de Dios no sea blasfemada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 6, 'Exhorta asimismo á los mancebos á que sean comedidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 7, 'Mostrándote en todo por ejemplo de buenas obras; en doctrina haciendo ver integridad, gravedad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 8, 'Palabra sana, é irreprensible; que el adversario se avergüence, no teniendo mal ninguno que decir de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 9, 'Exhorta á los siervos á que sean sujetos á sus señores, que agraden en todo, no respondones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 10, 'No defraudando, antes mostrando toda buena lealtad, para que adornen en todo la doctrina de nuestro Salvador Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 11, 'Porque la gracia de Dios que trae salvación á todos los hombres, se manifestó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 12, 'Enseñándonos que, renunciando á la impiedad y á los deseos mundanos, vivamos en este siglo templada, y justa, y píamente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 13, 'Esperando aquella esperanza bienaventurada, y la manifestación gloriosa del gran Dios y Salvador nuestro Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 14, 'Que se dió á sí mismo por nosotros para redimirnos de toda iniquidad, y limpiar para sí un pueblo propio, celoso de buenas obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 2, 15, 'Esto habla y exhorta, y reprende con toda autoridad. Nadie te desprecie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 1, 'AMONÉSTALES que se sujeten á los príncipes y potestades, que obedezcan, que estén prontos á toda buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 2, 'Que á nadie infamen, que no sean pendencieros, sino modestos, mostrando toda mansedumbre para con todos los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 3, 'Porque también éramos nosotros necios en otro tiempo, rebeldes, extraviados, sirviendo á concupiscencias y deleites diversos, viviendo en malicia y en envidia, aborrecibles, aborreciendo los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 4, 'Mas cuando se manifestó la bondad de Dios nuestro Salvador, y su amor para con los hombres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 5, 'No por obras de justicia que nosotros habíamos hecho, mas por su misericordia nos salvó, por el lavacro de la regeneración, y de la renovación del Espíritu Santo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 6, 'El cual derramó en nosotros abundantemente por Jesucristo nuestro Salvador,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 7, 'Para que, justificados por su gracia, seamos hechos herederos según la esperanza de la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 8, 'Palabra fiel, y estas cosas quiero que afirmes, para que los que creen á Dios procuren gobernarse en buenas obras. Estas cosas son buenas y útiles á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 9, 'Mas las cuestiones necias, y genealogías, y contenciones, y debates acerca de la ley, evita; porque son sin provecho y vanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 10, 'Rehusa hombre hereje, después de una y otra amonestación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 11, 'Estando cierto que el tal es trastornado, y peca, siendo condenado de su propio juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 12, 'Cuando enviare á ti á Artemas, ó á Tichîco, procura venir á mí, á Nicópolis: porque allí he determinado invernar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 13, 'A Zenas doctor de la ley, y á Apolos, envía delante, procurando que nada les falte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 14, 'Y aprendan asimismo los nuestros á gobernarse en buenas obras para los usos necesarios, para que no sean sin fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('TIT', 'Tito', 3, 15, 'Todos los que están conmigo te saludan. Saluda á los que nos aman en la fe. La gracia sea con todos vosotros. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 1, 'DIOS, habiendo hablado muchas veces y en muchas maneras en otro tiempo á los padres por los profetas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 2, 'En estos porstreros días nos ha hablado por el Hijo, al cual constituyó heredero de todo, por el cual asimismo hizo el universo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 3, 'El cual siendo el resplandor de su gloria, y la misma imagen de su sustancia, y sustentando todas las cosas con la palabra de su potencia, habiendo hecho la purgación de nuestros pecados por sí mismo, se sentó á la diestra de la Majestad en las alturas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 4, 'Hecho tanto más excelente que los ángeles, cuanto alcanzó por herencia más excelente nombre que ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 5, 'Porque ¿á cuál de los ángeles dijo Dios jamás: Mi hijo eres tú, Hoy yo te he engendrado? Y otra vez: Yo seré á él Padre, Y él me será á mí hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 6, 'Y otra vez, cuando introduce al Primogénito en la tierra, dice: Y adórenle todos los ángeles de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 7, 'Y ciertamente de los ángeles dice: El que hace á sus ángeles espíritus, Y á sus ministros llama de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 8, 'Mas al hijo: Tu trono, oh Dios, por el siglo del siglo; Vara de equidad la vara de tu reino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 9, 'Has amado la justicia, y aborrecido la maldad; Por lo cual te ungió Dios, el Dios tuyo, Con óleo de alegría más que á tus compañeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 10, 'Y: Tú, oh Señor, en el principio fundaste la tierra; Y los cielos son obras de tus manos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 11, 'Ellos perecerán, mas tú eres permanente; Y todos ellos se envejecerán como una vestidura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 12, 'Y como un vestido los envolverás, y serán mudados; Empero tú eres el mismo, Y tus años no acabarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 13, 'Pues, ¿á cuál de los ángeles dijo jamás: Siéntate á mi diestra, Hasta que ponga á tus enemigos por estrado de tus pies?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 1, 14, '¿No son todos espíritus administradores, enviados para servicio á favor de los que serán herederos de salud?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 1, 'POR tanto, es menester que con más diligencia atendamos á las cosas que hemos oído, porque acaso no nos escurramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 2, 'Porque si la palabra dicha por los ángeles fué firme, y toda rebeliíon y desobediencia recibió justa paga de retribución,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 3, '¿Cómo escaparemos nosotros, si tuviéremos en poco una salud tan grande? La cual, habiendo comenzado á ser publicada por el Señor, ha sido confirmada hasta nosotros por los que oyeron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 4, 'Testificando juntamente con ellos Dios, con señales y milagros, y diversas maravillas, y repartimientos del Espíritu Santo según su voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 5, 'Porque no sujetó á los ángeles el mundo venidero, del cual hablamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 6, 'Testificó empero uno en cierto lugar, diciendo: ¿Qué es el hombre, que te acuerdas de él? ¿O el hijo del hombre, que le visitas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 7, 'Tú le hiciste un poco menor que los ángeles, Coronástele de gloria y de honra, Y pusístete sobre las obras de tus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 8, 'Todas las cosas sujetaste debajo de sus pies. Porque en cuanto le sujetó todas las cosas, nada dejó que no sea sujeto á él; mas aun no vemos que todas las cosas le sean sujetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 9, 'Empero vemos coronado de gloria y de honra, por el padecimiento de muerte, á aquel Jesús que es hecho un poco menor que los ángeles, para que por gracia de Dios gustase la muerte por todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 10, 'Porque convenía que aquel por cuya causa son todas las cosas, y por el cual todas las cosas subsisten, habiendo de llevar á la gloria á muchos hijos, hiciese consumado por aflicciones al autor de la salud de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 11, 'Porque el que santifica y los que son santificados, de uno son todos: por lo cual no se avergüenza de llamarlos hermanos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 12, 'Diciendo: Anunciaré á mis hermanos tu nombre, En medio de la congregación te alabaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 13, 'Y otra vez: Yo confiaré en él. Y otra vez: He aquí, yo y los hijos que me dió Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 14, 'Así que, por cuanto los hijos participaron de carne y sangre, él también participó de lo mismo, para destruir por la muerte al que tenía el imperio de la muerte, es á saber, al diablo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 15, 'Y librar á los que por el temor de la muerte estaban por toda la vida sujetos á servidumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 16, 'Porque ciertamente no tomó á los ángeles, sino á la simiente de Abraham tomó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 17, 'Por lo cual, debía ser en todo semejante á los hermanos, para venir á ser misericordioso y fiel Pontífice en lo que es para con Dios, para expiar los pecados del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 2, 18, 'Porque en cuanto él mismo padeció siendo tentado, es poderoso para socorrer á los que son tentados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 1, 'POR tanto, hermanos santos, participantes de la vocación celestial, considerad al Apóstol y Pontífice de nuestra profesión, Cristo Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 2, 'El cual es fiel al que le constituyó, como también lo fué Moisés sobre toda su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 3, 'Porque de tanto mayor gloria que Moisés éste es estimado digno, cuanto tiene mayor dignidad que la casa el que la fabricó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 4, 'Porque toda casa es edificada de alguno: mas el que crió todas las cosas es Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 5, 'Y Moisés á la verdad fué fiel sobre toda su casa, como siervo, para testificar lo que se había de decir;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 6, 'Mas Cristo como hijo, sobre su casa; la cual casa somos nosotros, si hasta el cabo retuviéremos firme la confianza y la gloria de la esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 7, 'Por lo cual, como dice el Espíritu Santo: Si oyereis hoy su voz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 8, 'No endurezcáis vuestros corazones Como en la provocación, en el día de la tentación en el desierto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 9, 'Donde me tentaron vuestros padres; me probaron, Y vieron mis obras cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 10, 'A causa de lo cual me enemisté con esta generación, Y dije: Siempre divagan ellos de corazón, Y no han conocido mis caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 11, 'Juré, pues, en mi ira: No entrarán en mi reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 12, 'Mirad, hermanos, que en ninguno de vosotros haya corazón malo de incredulidad para apartarse del Dios vivo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 13, 'Antes exhortaos los unos á los otros cada día, entre tanto que se dice Hoy; porque ninguno de vosotros se endurezca con engaño de pecado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 14, 'Porque participantes de Cristo somos hechos, con tal que conservemos firme hasta el fin el principio de nuestra confianza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 15, 'Entre tanto que se dice: Si oyereis hoy su voz, No endurezcáis vuestros corazones, como en la provocación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 16, 'Porque algunos de los que habían salido de Egipto con Moisés, habiendo oído, provocaron, aunque no todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 17, 'Mas ¿con cuáles estuvo enojado cuarenta años? ¿No fué con los que pecaron, cuyos cuerpos cayeron en el desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 18, '¿Y á quiénes juró que no entrarían en su reposo, sino á aquellos que no obedecieron?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 3, 19, 'Y vemos que no pudieron entrar á causa de incredulidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 1, 'TEMAMOS, pues, que quedando aún la promesa de entrar en su reposo, parezca alguno de vosotros haberse apartado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 2, 'Porque también á nosotros se nos ha evangelizado como á ellos; mas no les aprovechó el oir la palabra á los que la oyeron sin mezclar fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 3, 'Empero entramos en el reposo los que hemos creído, de la manera que dijo: Como juré en mi ira, No entrarán en mi reposo: aun acabadas las obras desde el principio del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 4, 'Porque en un cierto lugar dijo así del séptimo día: Y reposó Dios de todas sus obras en el séptimo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 5, 'Y otra vez aquí: No entrarán en mi reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 6, 'Así que, pues que resta que algunos han de entrar en él, y aquellos á quienes primero fué anunciado no entraron por causa de desobediencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 7, 'Determina otra vez un cierto día, diciendo por David: Hoy, después de tanto tiempo; como está dicho: Si oyereis su voz hoy, No endurezcáis vuestros corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 8, 'Porque si Josué les hubiera dado el reposo, no hablaría después de otro día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 9, 'Por tanto, queda un reposo para el pueblo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 10, 'Porque el que ha entrado en su reposo, también él ha reposado de sus obras, como Dios de las suyas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 11, 'Procuremos pues de entrar en aquel reposo; que ninguno caiga en semejante ejemplo de desobediencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 12, 'Porque la palabra de Dios es viva y eficaz, y más penetrante que toda espada de dos filos: y que alcanza hasta partir el alma, y aun el espíritu, y las coyunturas y tuétanos, y discierne los pensamientos y las intenciones del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 13, 'Y no hay cosa criada que no sea manifiesta en su presencia; antes todas las cosas están desnudas y abiertas á los ojos de aquel á quien tenemos que dar cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 14, 'Por tanto, teniendo un gran Pontífice, que penetró los cielos, Jesús el Hijo de Dios, retengamos nuestra profesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 15, 'Porque no tenemos un Pontífice que no se pueda compadecer de nuestras flaquezas; mas tentado en todo según nuestra semejanza, pero sin pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 4, 16, 'Lleguémonos pues confiadamente al trono de la gracia, para alcanzar misericordia, y hallar gracia para el oportuno socorro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 1, 'PORQUE todo pontífice, tomado de entre los hombres, es constituído á favor de los hombres en lo que á Dios toca, para que ofrezca presentes y sacrificios por los pecados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 2, 'Que se pueda compadecer de los ignorantes y extraviados, pues que él también está rodeado de flaqueza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 3, 'Y por causa de ella debe, como por sí mismo, así también por el pueblo, ofrecer por los pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 4, 'Ni nadie toma para sí la honra, sino el que es llamado de Dios, como Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 5, 'Así también Cristo no se glorificó á sí mismo haciéndose Pontífice, mas el que le dijo: Tú eres mi Hijo, Yo te he engendrado hoy;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 6, 'Como también dice en otro lugar: Tú eres sacerdote eternamente, Según el orden de Melchîsedec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 7, 'El cual en los días de su carne, ofreciendo ruegos y súplicas con gran clamor y lágrimas al que le podía librar de la muerte, fué oído por su reverencial miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 8, 'Y aunque era Hijo, por lo que padeció aprendió la obediencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 9, 'Y consumado, vino á ser causa de eterna salud á todos los que le obedecen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 10, 'Nombrado de Dios pontífice según el orden de Melchîsedec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 11, 'Del cual tenemos mucho que decir, y dificultoso de declarar, por cuanto sois flacos para oir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 12, 'Porque debiendo ser ya maestros á causa del tiempo, tenéis necesidad de volver á ser enseñados cuáles sean los primeros rudimentos de las palabras de Dios; y habéis llegado á ser tales que tengáis necesidad de leche, y no de manjar sólido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 13, 'Que cualquiera que participa de la leche, es inhábil para la palabra de la justicia, porque es niño;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 5, 14, 'Mas la vianda firme es para los perfectos, para los que por la costumbre tienen los sentidos ejercitados en el discernimiento del bien y del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 1, 'POR tanto, dejando la palabra del comienzo en la doctrina de Cristo, vamos adelante á la perfección; no echando otra vez el fundamento; no arrepentimiento de obras muertas, y de la fe en Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 2, 'De la doctrina de bautismos, y de la imposición de manos, y de la resurrección de los muertos, y del juicio eterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 3, 'Y esto haremos á la verdad, si Dios lo permitiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 4, 'Porque es imposible que los que una vez fueron iluminados y gustaron el don celestial, y fueron hechos partícipes del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 5, 'Y asimismo gustaron la buena palabra de Dios, y las virtudes del siglo venidero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 6, 'Y recayeron, sean otra vez renovados para arrepentimiento, crucificando de nuevo para sí mismos al Hijo de Dios, y exponiéndole á vituperio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 7, 'Porque la tierra que embebe el agua que muchas veces vino sobre ella, y produce hierba provechosa á aquellos de los cuales es labrada, recibe bendición de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 8, 'Mas la que produce espinas y abrojos, es reprobada, y cercana de maldición; cuyo fin será el ser abrasada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 9, 'Pero de vosotros, oh amados, esperamos mejores cosas, y más cercanas á salud, aunque hablamos así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 10, 'Porque Dios no es injusto para olvidar vuestra obra y el trabajo de amor que habéis mostrado á su nombre, habiendo asistido y asistiendo aún á los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 11, 'Mas deseamos que cada uno de vosotros muestre la misma solicitud hasta el cabo, para cumplimiento de la esperanza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 12, 'Que no os hagáis perezosos, mas imitadores de aquellos que por la fe y la paciencia heredan las promesas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 13, 'Porque prometiendo Dios á Abraham, no pudiendo jurar por otro mayor, juró por sí mismo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 14, 'Diciendo: De cierto te bendeciré bendiciendo, y multiplicando te multiplicaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 15, 'Y así, esperando con largura de ánimo, alcanzó la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 16, 'Porque los hombres ciertamente por el mayor que ellos juran: y el fin de todas sus controversias es el juramento para confirmación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 17, 'Por lo cual, queriendo Dios mostrar más abundantemente á los herederos de la promesa la inmutabilidad de su consejo, interpuso juramento;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 18, 'Para que por dos cosas inmutables, en las cuales es imposible que Dios mienta, tengamos un fortísimo consuelo, los que nos acogemos á trabarnos de la esperanza propuesta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 19, 'La cual tenemos como segura y firme ancla del alma, y que entra hasta dentro del velo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 6, 20, 'Donde entró por nosotros como precursor Jesús, hecho Pontífice eternalmente según el orden de Melchîsedec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 1, 'PORQUE este Melchîsedec, rey de Salem, sacerdote del Dios Altísimo, el cual salió á recibir á Abraham que volvía de la derrota de los reyes, y le bendijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 2, 'Al cual asimismo dió Abraham los diezmos de todo, primeramente él se interpreta Rey de justicia; y luego también Rey de Salem, que es, Rey de paz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 3, 'Sin padre, sin madre, sin linaje; que ni tiene principio de días, ni fin de vida, mas hecho semejante al Hijo de Dios, permanece sacerdote para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 4, 'Mirad pues cuán grande fué éste, al cual aun Abraham el patriarca dió diezmos de los despojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 5, 'Y ciertamente los que de los hijos de Leví toman el sacerdocio, tienen mandamiento de tomar del pueblo los diezmos según la ley, es á saber, de sus hermanos aunque también hayan salido de los lomos de Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 6, 'Mas aquél cuya genealogía no es contada de ellos, tomó de Abraham los diezmos, y bendijo al que tenía las promesas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 7, 'Y sin contradicción alguna, lo que es menos es bendecido de lo que es más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 8, 'Y aquí ciertamente los hombres mortales toman los diezmos: mas allí, aquel del cual está dado testimonio que vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 9, 'Y, por decirlo así, en Abraham fué diezmado también Leví, que recibe los diezmos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 10, 'Porque aun estaba en los lomos de su padre cuando Melchîsedec le salió al encuentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 11, 'Si pues la perfección era por el sacerdocio Levítico (porque debajo de él recibio el pueblo la ley) ¿qué necesidad había aún de que se levantase otro sacerdote según el orden de Melchîsedec, y que no fuese llamado según el orden de Aarón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 12, 'Pues mudado el sacerdocio, necesario es que se haga también mudanza de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 13, 'Porque aquel del cual esto se dice, de otra tribu es, de la cual nadie asistió al altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 14, 'Porque notorio es que el Señor nuestro nació de la tribu de Judá, sobre cuya tribu nada habló Moisés tocante al sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 15, 'Y aun más manifiesto es, si á semejanza de Melchîsedec se levanta otro sacerdote,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 16, 'El cual no es hecho conforme á la ley del mandamiento carnal, sino según la virtud de vida indisoluble;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 17, 'Pues se da testimonio de él: Tú eres sacerdote para siempre, Según el orden de Melchîsedec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 18, 'El mandamiento precedente, cierto se abroga por su flaqueza é inutilidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 19, 'Porque nada perfeccionó la ley; mas hízolo la introducción de mejor esperanza, por la cual nos acercamos á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 20, 'Y por cuanto no fué sin juramento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 21, '(Porque los otros cierto sin juramento fueron hechos sacerdotes; mas éste, con juramento por el que le dijo: Juró el Señor, y no se arrepentirá: Tú eres sacerdote eternamente Según el orden de Melchîsedec:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 22, 'Tanto de mejor testamento es hecho fiador Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 23, 'Y los otros cierto fueron muchos sacerdotes, en cuanto por la muerte no podían permanecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 24, 'Mas éste, por cuanto permanece para siempre, tiene un sacerdocio inmutable:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 25, 'Por lo cual puede también salvar eternamente á los que por él se allegan á Dios, viviendo siempre para interceder por ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 26, 'Porque tal pontífice nos convenía: santo, inocente, limpio, apartado de los pecadores, y hecho más sublime de los cielos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 27, 'Que no tiene necesidad cada día, como los otros sacerdotes, de ofrecer primero sacrificios por sus pecados, y luego por los del pueblo: porque esto lo hizo una sola vez, ofreciéndose á sí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 7, 28, 'Porque la ley constituye sacerdotes á hombres flacos; mas la palabra del juramento, después de la ley, constituye al Hijo, hecho perfecto para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 1, 'ASI que, la suma acerca de lo dicho es: Tenemos tal pontífice que se asentó á la diestra del trono de la Majestad en los cielos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 2, 'Ministro del santuario, y de aquel verdadero tabernáculo que el Señor asentó, y no hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 3, 'Porque todo pontífice es puesto para ofrecer presentes y sacrificios; por lo cual es necesario que también éste tuviese algo que ofrecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 4, 'Así que, si estuviese sobre la tierra, ni aun sería sacerdote, habiendo aún los sacerdotes que ofrecen los presentes según la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 5, 'Los cuales sirven de bosquejo y sombre de las cosas celestiales, como fué respondido á Moisés cuando había de acabar el tabernáculo: Mira, dice, haz todas las cosas conforme al dechado que te ha sido mostrado en el monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 6, 'Mas ahora tanto mejor ministerio es el suyo, cuanto es mediador de un mejor pacto, el cual ha sido formado sobre mejores promesas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 7, 'Porque si aquel primero fuera sin falta, cierto no se hubiera procurado lugar de segundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 8, 'Porque reprendiéndolos dice: He aquí vienen días, dice el Señor, Y consumaré para con la casa de Israel y para con la casa de Judá un nuevo pacto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 9, 'No como el pacto que hice con sus padres El día que los tomé por la mano para sacarlos de la tierra de Egipto: Porque ellos no permanecieron en mi pacto, Y yo los menosprecié, dice el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 10, 'Por lo cual, este es el pacto que ordenaré á la casa de Israel Después de aquellos días, dice el Señor: Daré mis leyes en el alma de ellos, Y sobre el corazón de ellos las escribiré; Y seré á ellos por Dios, Y ellos me serán á mí por pueblo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 11, 'Y ninguno eneseñará á su prójimo, Ni ninguno á su hermano, diciendo: Conoce al Señor: Porque todos me conocerán, Desde el menor de ellos hasta el mayor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 12, 'Porque seré propicio á sus injusticias, Y de sus pecados y de sus iniquidades no me acordaré más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 8, 13, 'Diciendo, Nuevo pacto, dió por viejo al primero; y lo que es dado por viejo y se envejece, cerca está de desvanecerse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 1, 'TENIA empero también el primer pacto reglamentos del culto, y santuario mundano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 2, 'Porque el tabernáculo fué hecho: el primero, en que estaban las lámparas, y la mesa, y los panes de la proposición; lo que llaman el Santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 3, 'Tras el segundo velo estaba el tabernáculo, que llaman el Lugar Santísimo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 4, 'El cual tenía un incensario de oro, y el arca del pacto cubierta de todas partes alrededor de oro; en la que estaba una urna de oro que contenía el maná, y la vara de Aarón que reverdeció, y las tablas del pacto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 5, 'Y sobre ella los querubines de gloria que cubrían el propiciatorio; de las cuales cosas no se puede ahora hablar en particular.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 6, 'Y estas cosas así ordenadas, en el primer tabernáculo siempre entraban los sacerdotes para hacer los oficios del culto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 7, 'Mas en el segundo, sólo el pontífice una vez en el año, no sin sangre, la cual ofrece por sí mismo, y por los pecados de ignorancia del pueblo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 8, 'Dando en esto á entender el Espíritu Santo, que aun no estaba descubierto el camino para el santuario, entre tanto que el primer tabernáculo estuviese en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 9, 'Lo cual era figura de aquel tiempo presente, en el cual se ofrecían presentes y sacrificios que no podían hacer perfecto, cuanto á la conciencia, al que servía con ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 10, 'Consistiendo sólo en viandas y en bebidas, y en diversos lavamientos, y ordenanzas acerca de la carne, impuestas hasta el tiempo de la corrección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 11, 'Mas estando ya presente Cristo, pontífice de los bienes que habían de venir, por el más amplio y más perfecto tabernáculo, no hecho de manos, es á saber, no de esta creación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 12, 'Y no por sangre de machos cabríos ni de becerros, mas por su propia sangre, entró una sola vez en el santuario, habiendo obtenido eterna redención.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 13, 'Porque si la sangre de los toros y de los machos cabríos, y la ceniza de la becerra, rociada á los inmundos, santifica para la purificación de la carne,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 14, '¿Cuánto más la sangre de Cristo, el cual por el Espíritu eterno se ofreció á sí mismo sin mancha á Dios, limpiará vuestras conciencias de las obras de muerte para que sirváis al Dios vivo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 15, 'Así que, por eso es mediador del nuevo testamento, para que interviniendo muerte para la remisión de las rebeliones que había bajo del primer testamento, los que son llamados reciban la promesa de la herencia eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 16, 'Porque donde hay testamento, necesario es que intervenga muerte del testador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 17, 'Porque el testamento con la muerte es confirmado; de otra manera no es válido entre tanto que el testador vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 18, 'De donde vino que ni aun el primero fué consagrado sin sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 19, 'Porque habiendo leído Moisés todos los mandamientos de la ley á todo el pueblo, tomando la sangre de los becerros y de los machos cabríos, con agua, y lana de grana, é hisopo, roció al mismo libro, y también á todo el pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 20, 'Diciendo: Esta es la sangre del testamento que Dios os ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 21, 'Y además de esto roció también con la sangre el tabernáculo y todos los vasos del ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 22, 'Y casi todo es purificado según la ley con sangre; y sin derramamiento de sangre no se hace remisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 23, 'Fué, pues, necesario que las figuras de las cosas celestiales fuesen purificadas con estas cosas; empero las mismas cosas celestiales con mejores sacrificios que éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 24, 'Porque no entró Cristo en el santuario hecho de mano, figura del verdadero, sino en el mismo cielo para presentarse ahora por nosotros en la presencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 25, 'Y no para ofrecerse muchas veces á sí mismo, como entra el pontífice en el santuario cada año con sangre ajena;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 26, 'De otra manera fuera necesario que hubiera padecido muchas veces desde el principio del mundo: mas ahora una vez en la consumación de los siglos, para deshacimiento del pecado se presentó por el sacrificio de sí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 27, 'Y de la manera que está establecido á los hombres que mueran una vez, y después el juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 9, 28, 'Así también Cristo fué ofrecido una vez para agotar los pecados de muchos; y la segunda vez, sin pecado, será visto de los que le esperan para salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 1, 'PORQUE la ley, teniendo la sombra de los bienes venideros, no la imagen misma de las cosas, nunca puede, por los mismos sacrificios que ofrecen continuamente cada año, hacer perfectos á los que se allegan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 2, 'De otra manera cesarían de ofrecerse; porque los que tributan este culto, limpios de una vez, no tendrían más conciencia de pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 3, 'Empero en estos sacrificios cada año se hace conmemoración de los pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 4, 'Porque la sangre de los toros y de los machos cabríos no puede quitar los pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 5, 'Por lo cual, entrando en el mundo, dice: sacrificio y presente no quisiste; Mas me apropiaste cuerpo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 6, 'Holocaustos y expiaciones por el pecado no te agradaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 7, 'Entonces dije: Heme aquí (En la cabecera del libro está escrito de mí) Para que haga, oh Dios, tu voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 8, 'Diciendo arriba: Sacrificio y presente, y holocaustos y expiaciones por el pecado no quisiste, ni te agradaron, (las cuales cosas se ofrecen según la ley,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 9, 'Entonces dijo: Heme aquí para que haga, oh Dios, tu voluntad. Quita lo primero, para establecer lo postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 10, 'En la cual voluntad somos santificados por la ofrenda del cuerpo de Jesucristo hecha una sola vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 11, 'Así que, todo sacerdote se presenta cada día ministrando y ofreciendo muchas veces los mismos sacrificios, que nunca pueden quitar los pecados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 12, 'Pero éste, habiendo ofrecido por los pecados un solo sacrificio para siempre, está sentado á la diestra de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 13, 'Esperando lo que resta, hasta que sus enemigos sean puestos por estrado de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 14, 'Porque con una sola ofrenda hizo perfectos para siempre á los santificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 15, 'Y atestíguanos lo mismo el Espíritu Santo; que después que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 16, 'Y este es el pacto que haré con ellos Después de aquellos días, dice el Señor: Daré mis leyes en sus corazones, Y en sus almas las escribiré:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 17, 'Añade: Y nunca más me acordaré de sus pecados é iniquidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 18, 'Pues donde hay remisión de éstos, no hay más ofrenda por pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 19, 'Así que, hermanos, teniendo libertad para entrar en el santuario por la sangre de Jesucristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 20, 'Por el camino que él nos consagró nuevo y vivo, por el velo, esto es, por su carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 21, 'Y teniendo un gran sacerdote sobre la casa de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 22, 'Lleguémonos con corazón verdadero, en plena certidumbre de fe, purificados los corazones de mala conciencia, y lavados los cuerpos con agua limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 23, 'Mantengamos firme la profesión de nuestra fe sin fluctuar; que fiel es el que prometió:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 24, 'Y considerémonos los unos á los otros para provocarnos al amor y á las buenas obras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 25, 'No dejando nuestra congregación, como algunos tienen por costumbre, mas exhortándonos; y tanto más, cuanto veis que aquel día se acerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 26, 'Porque si pecáremos voluntariamente después de haber recibido el conocimiento de la verdad, ya no queda sacrificio por el pecado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 27, 'Sino una horrenda esperanza de juicio, y hervor de fuego que ha de devorar á los adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 28, 'El que menospreciare la ley de Moisés, por el testimonio de dos ó de tres testigos muere sin ninguna misericordia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 29, '¿Cuánto pensáis que será más digno de mayor castigo, el que hollare al Hijo de Dios, y tuviere por inmunda la sangre del testamento, en la cual fué santificado, é hiciere afrenta al Espíritu de gracia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 30, 'Sabemos quién es el que dijo: Mía es la venganza, yo daré el pago, dice el Señor. Y otra vez: El Señor juzgará su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 31, 'Horrenda cosa es caer en las manos del Dios vivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 32, 'Empero traed á la memoria los días pasados, en los cuales, después de haber sido iluminados, sufristeis gran combate de aflicciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 33, 'Por una parte, ciertamente, con vituperios y tribulaciones fuisteis hechos espectáculo; y por otra parte hechos compañeros de los que estaban en tal estado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 34, 'Porque de mis prisiones también os resentisteis conmigo, y el robo de vuestros bienes padecisteis con gozo, conociendo que tenéis en vosotros una mejor sustancia en los cielos, y que permanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 35, 'No perdáis pues vuestra confianza, que tiene grande remuneración de galardón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 36, 'Porque la paciencia os es necesaria; para que, habiendo hecho la voluntad de Dios, obtengáis la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 37, 'Porque aun un poquito, Y el que ha de venir vendrá, y no tardará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 38, 'Ahora el justo vivirá por fe; Mas si se retirare, no agradará á mi alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 10, 39, 'Pero nosotros no somos tales que nos retiremos para perdición, sino fieles para ganancia del alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 1, 'ES pues la fe la sustancia de las cosas que se esperan, la demostración de las cosas que no se ven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 2, 'Porque por ella alcanzaron testimonio los antiguos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 3, 'Por la fe entendemos haber sido compuestos los siglos por la palabra de Dios, siendo hecho lo que se ve, de lo que no se veía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 4, 'Por la fe Abel ofreció á Dios mayor sacrificio que Caín, por la cual alcanzó testimonio de que era justo, dando Dios testimonio á sus presentes; y difunto, aun habla por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 5, 'Por la fe Enoc fué traspuesto para no ver muerte, y no fué hallado, porque lo traspuso Dios. Y antes que fuese traspuesto, tuvo testimonio de haber agradado á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 6, 'Empero sin fe es imposible agradar á Dios; porque es menester que el que á Dios se allega, crea que le hay, y que es galardonador de los que le buscan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 7, 'Por la fe Noé, habiendo recibido respuesta de cosas que aun no se veían, con temor aparejó el arca en que su casa se salvase: por la cual fe condenó al mundo, y fué hecho heredero de la justicia que es por la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 8, 'Por la fe Abraham, siendo llamado, obedeció para salir al lugar que había de recibir por heredad; y salió sin saber dónde iba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 9, 'Por fe habitó en la tierra prometida como en tierra ajena, morando en cabañas con Isaac y Jacob, herederos juntamente de la misma promesa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 10, 'Porque esperaba ciudad con fundamentos, el artífice y hacedor de la cual es Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 11, 'Por la fe también la misma Sara, siendo estéril, recibió fuerza para concebir simiente; y parió aun fuera del tiempo de la edad, porque creyó ser fiel el que lo había prometido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 12, 'Por lo cual también, de uno, y ése ya amortecido, salieron como las estrellas del cielo en multitud, y como la arena inmunerable que está á la orilla de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 13, 'Conforme á la fe murieron todos éstos sin haber recibido las promesas, sino mirándolas de lejos, y creyéndolas, y saludándolas, y confesando que eran peregrinos y advenedizos sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 14, 'Porque los que esto dicen, claramente dan á entender que buscan una patria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 15, 'Que si se acordaran de aquella de donde salieron, cierto tenían tiempo para volverse:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 16, 'Empero deseaban la mejor, es á saber, la celestial; por lo cual Dios no se avergüenza de llamarse Dios de ellos: porque les había aparejado ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 17, 'Por fe ofreció Abraham á Isaac cuando fué probado, y ofrecía al unigénito el que había recibido las promesas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 18, 'Habiéndole sido dicho: En Isaac te será llamada simiente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 19, 'Pensando que aun de los muertos es Dios poderoso para levantar; de donde también le volvió á recibir por figura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 20, 'Por fe bendijo Isaac á Jacob y á Esaú respecto á cosas que habían de ser.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 21, 'Por fe Jacob, muriéndose, bendijo á cada uno de los hijos de José, y adoró estribando sobre la punta de su bordón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 22, 'Por fe José, muriéndose, se acordó de la partida de los hijos de Israel; y dió mandamiento acerca de sus huesos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 23, 'Por fe Moisés, nacido, fué escondido de sus padres por tres meses, porque le vieron hermoso niño; y no temieron el mandamiento del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 24, 'Por fe Moisés, hecho ya grande, rehusó ser llamado hijo de la hija de Faraón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 25, 'Escogiendo antes ser afligido con el pueblo de Dios, que gozar de comodidades temporales de pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 26, 'Teniendo por mayores riquezas el vituperio de Cristo que los tesoros de los Egipcios; porque miraba á la remuneración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 27, 'Por fe dejó á Egipto, no temiendo la ira del rey; porque se sostuvo como viendo al Invisible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 28, 'Por fe celebró la pascua y el derramamiento de la sangre, para que el que mataba los primogénitos no los tocase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 29, 'Por fe pasaron el mar Bermejo como por tierra seca: lo cual probando los Egipcios, fueron sumergidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 30, 'Por fe cayeron los muros de Jericó con rodearlos siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 31, 'Por fe Rahab la ramera no pereció juntamente con los incrédulos, habiendo recibido á los espías con paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 32, '¿Y qué más digo? porque el tiempo me faltará contando de Gedeón, de Barac, de Samsón, de Jephté, de David, de Samuel, y de los profetas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 33, 'Que por fe ganaron reinos, obraron justicia, alcanzaron promesas, taparon las bocas de leones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 34, 'Apagaron fuegos impetuosos, evitaron filo de cuchillo, convalecieron de enfermedades, fueron hechos fuertes en batallas, trastornaron campos de extraños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 35, 'Las mujeres recibieron sus muertos por resurrección; unos fueron estirados, no aceptando el rescate, para ganar mejor resurrección;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 36, 'Otros experimentaron vituperios y azotes; y á más de esto prisiones y cárceles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 37, 'Fueron apedreados, aserrados, tentados, muertos á cuchillo; anduvieron de acá para allá cubiertos de pieles de ovejas y de cabras, pobres, angustiados, maltratados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 38, 'De los cuales el mundo no era digno; perdidos por los desiertos, por los montes, por las cuevas y por las cavernas de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 39, 'Y todos éstos, aprobados por testimonio de la fe, no recibieron la promesa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 11, 40, 'Proveyendo Dios alguna cosa mejor para nosotros, para que no fuesen perfeccionados sin nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 1, 'POR tanto nosotros también, teniendo en derredor nuestro una tan grande nube de testigos, dejando todo el peso del pecado que nos rodea, corramos con paciencia la carrera que nos es propuesta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 2, 'Puestos los ojos en al autor y consumador de la fe, en Jesús; el cual, habiéndole sido propuesto gozo, sufrió la cruz, menospreciando la vergüenza, y sentóse á la diestra del trono de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 3, 'Reducid pues á vuestro pensameinto á aquel que sufrió tal contradicción de pecadores contra sí mismo, porque no os fatiguéis en vuestros ánimos desmayando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 4, 'Que aun no habéis resistido hasta la sangre, combatiendo contra el pecado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 5, 'Y estáis ya olvidados de la exhortación que como con hijos habla con vosotros, diciendo: Hijo mío, no menosprecies el castigo del Señor, Ni desmayes cuando eres de él reprendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 6, 'Porque el Señor al que ama castiga, Y azota á cualquiera que recibe por hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 7, 'Si sufrís el castigo, Dios se os presenta como á hijos; porque ¿qué hijo es aquel á quien el padre no castiga?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 8, 'Mas si estáis fuera del castigo, del cual todos han sido hechos participantes, luego sois bastardos, y no hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 9, 'Por otra parte, tuvimos por castigadores á los padres de nuestra carne, y los reverenciábamos, ¿por qué no obedeceremos mucho mejor al Padre de los espíritus, y viviremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 10, 'Y aquéllos, á la verdad, por pocos días nos castigaban como á ellos les parecía, mas éste para lo que nos es provechoso, para que recibamos su santificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 11, 'Es verdad que ningún castigo al presente parece ser causa de gozo, sino de tristeza; mas después da fruto apacible de justicia á los que en él son ejercitados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 12, 'Por lo cual alzad las manos caídas y las rodillas paralizadas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 13, 'Y haced derechos pasos á vuestros pies, porque lo que es cojo no salga fuera de camino, antes sea sanado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 14, 'Seguid la paz con todos, y la santidad, sin la cual nadie verá al Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 15, 'Mirando bien que ninguno se aparte de la gracia de Dios, que ninguna raíz de amargura brotando os impida, y por ella muchos sean contaminados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 16, 'Que ninguno sea fornicario, ó profano, como Esaú, que por una vianda vendió su primogenitura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 17, 'Porque ya sabéis que aun después, deseando heredar la bendición, fue reprobado (que no halló lugar de arrepentimiento), aunque la procuró con lágrimas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 18, 'Porque no os habéis llegado al monte que se podía tocar, y al fuego encendido, y al turbión, y á la oscuridad, y á la tempestad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 19, 'Y al sonido de la trompeta, y á la voz de las palabras, la cual los que la oyeron rogaron que no se les hablase más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 20, 'Porque no podían tolerar lo que se mandaba: Si bestia tocare al monte, será apedreada, ó pasada con dardo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 21, 'Y tan terrible cosa era lo que se veía, que Moisés dijo: Estoy asombrado y temblando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 22, 'Mas os habéis llegado al monte de Sión, y á la ciudad del Dios vivo, Jerusalem la celestial, y á la compañía de muchos millares de ángeles,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 23, 'Y á la congregación de los primogénitos que están alistados en los cielos, y á Dios el Juez de todos, y á los espíritus de los justos hechos perfectos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 24, 'Y á Jesús el Mediador del nuevo testamento, y á la sangre del esparcimiento que habla mejor que la de Abel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 25, 'Mirad que no desechéis al que habla. Porque si aquellos no escaparon que desecharon al que hablaba en la tierra, mucho menos nosotros, si desecháramos al que habla de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 26, 'La voz del cual entonces conmovió la tierra; mas ahora ha denunciado, diciendo: Aun una vez, y yo conmoveré no solamente la tierra, mas aun el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 27, 'Y esta palabra, Aun una vez, declara la mudanza de las cosas movibles, como de cosas que son firmes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 28, 'Así que, tomando el reino inmóvil, vamos á Dios agradándole con temor y reverencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 12, 29, 'Porque nuestro Dios es fuego consumidor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 1, 'PERMANEZCA el amor fraternal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 2, 'No olvidéis la hospitalidad, porque por ésta algunos, sin saberlo, hospedaron ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 3, 'Acordaos de los presos, como presos juntamente con ellos; y de los afligidos, como que también vosotros mismos sois del cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 4, 'Honroso es en todos el matrimonio, y el lecho sin mancilla; ·mas á los fornicarios y á los adúlteros juzgará Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 5, 'Sean las costumbres vuestras sin avaricia; contentos de lo presente; porque él dijo: No te desampararé, ni te dejaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 6, 'De tal manera que digamos confiadamente: El Señor es mi ayudador; no temeré Lo que me hará el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 7, 'Acordaos de vuestros pastores, que os hablaron la palabra de Dios; la fe de los cuales imitad, considerando cuál haya sido el éxito de su conducta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 8, 'Jesucristo es el mismo ayer, y hoy, y por los siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 9, 'No seáis llevados de acá para allá por doctrinas diversas y extrañas; porque buena cosa es afirmar el corazón en la gracia, no en viandas, que nunca aprovecharon á los que anduvieron en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 10, 'Tenemos un altar, del cual no tienen facultad de comer los que sirven al tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 11, 'Porque los cuerpos de aquellos animales, la sangre de los cuales es metida por el pecado en el santuario por el pontífice, son quemados fuera del real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 12, 'Por lo cual también Jesús, para santificar al pueblo por su propia sangre, padeció fuera de la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 13, 'Salgamos pues á él fuera del real, llevando su vituperio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 14, 'Porque no tenemos aquí ciudad permanente, mas buscamos la por venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 15, 'Así que, ofrezcamos por medio de él á Dios siempre sacrificio de alabanza, es á saber, fruto de labios que confiesen á su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 16, 'Y de hacer bien y de la comunicación no os olvidéis: porque de tales sacrificios se agrada Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 17, 'Obedeced á vuestros pastores, y sujetaos á ellos; porque ellos velan por vuestras almas, como aquellos que han de dar cuenta; para que lo hagan con alegría, y no gimiendo; porque esto no os es útil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 18, 'Orad por nosotros: porque confiamos que tenemos buena conciencia, deseando conversar bien en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 19, 'Y más os ruego que lo hagáis así, para que yo os sea más presto restituído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 20, 'Y el Dios de paz que sacó de los muertos á nuestro Señor Jesucristo, el gran pastor de las ovejas, por la sangre del testamento eterno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 21, 'Os haga aptos en toda obra buena para que hagáis su voluntad, haciendo él en vosotros lo que es agradable delante de él por Jesucristo: al cual sea gloria por los siglos de los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 22, 'Empero os ruego, hermanos, que soportéis la palabra de exhortación; porque os he escrito en breve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 23, 'Sabed que nuestro hermano Timoteo está suelto; con el cual, si viniere más presto, os iré á ver.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 24, 'Saludad á todos vuestros pastores, y á todos los santos. Los de Italia os saludan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('HEB', 'Hebreos', 13, 25, 'La gracia sea con todos vosotros. Amén.');
